const JoystickSubstrate = (function() {
    'use strict';


    let _active = false;
    let _startX = 0;
    let _startY = 0;
    let _currentX = 0;
    let _currentY = 0;
    let _deadzone = 0.1;
    let _maxRadius = 50;


    let _outputX = 0;
    let _outputY = 0;


    let _container = null;
    let _base = null;
    let _stick = null;


    let _onMove = null;
    let _onRelease = null;

    const STYLES = `
        .joystick-container {
            position: fixed;
            bottom: 20px;
            left: 20px;
            width: 120px;
            height: 120px;
            z-index: 1000;
            touch-action: none;
        }
        .joystick-base {
            position: absolute;
            width: 100%;
            height: 100%;
            background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0.05) 100%);
            border: 2px solid rgba(255,255,255,0.3);
            border-radius: 50%;
        }
        .joystick-stick {
            position: absolute;
            width: 50px;
            height: 50px;
            background: radial-gradient(circle, rgba(0,255,200,0.8) 0%, rgba(0,200,150,0.6) 100%);
            border: 2px solid rgba(0,255,200,0.9);
            border-radius: 50%;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            transition: transform 0.05s ease-out;
            box-shadow: 0 0 15px rgba(0,255,200,0.5);
        }
        .joystick-stick.active {
            transform: translate(-50%, -50%);
            transition: none;
        }
        .joystick-label {
            position: absolute;
            bottom: -25px;
            width: 100%;
            text-align: center;
            color: rgba(255,255,255,0.6);
            font-size: 12px;
            font-family: sans-serif;
        }
    `;


    function create(options = {}) {
        const position = options.position || 'left';
        const label = options.label || 'Move';


        if (!document.getElementById('joystick-styles')) {
            const style = document.createElement('style');
            style.id = 'joystick-styles';
            style.textContent = STYLES;
            document.head.appendChild(style);
        }


        _container = document.createElement('div');
        _container.className = 'joystick-container';
        if (position === 'right') {
            _container.style.left = 'auto';
            _container.style.right = '20px';
        }

        _base = document.createElement('div');
        _base.className = 'joystick-base';

        _stick = document.createElement('div');
        _stick.className = 'joystick-stick';

        const labelEl = document.createElement('div');
        labelEl.className = 'joystick-label';
        labelEl.textContent = label;

        _container.appendChild(_base);
        _container.appendChild(_stick);
        _container.appendChild(labelEl);
        document.body.appendChild(_container);


        _container.addEventListener('mousedown', onStart);
        _container.addEventListener('touchstart', onStart, { passive: false });
        window.addEventListener('mousemove', onMove);
        window.addEventListener('touchmove', onMove, { passive: false });
        window.addEventListener('mouseup', onEnd);
        window.addEventListener('touchend', onEnd);

        return _container;
    }

    function onStart(e) {
        e.preventDefault();
        _active = true;
        _stick.classList.add('active');

        const rect = _container.getBoundingClientRect();
        const touch = e.touches ? e.touches[0] : e;
        _startX = rect.left + rect.width / 2;
        _startY = rect.top + rect.height / 2;

        onMove(e);
    }

    function onMove(e) {
        if (!_active) return;
        e.preventDefault();

        const touch = e.touches ? e.touches[0] : e;
        const dx = touch.clientX - _startX;
        const dy = touch.clientY - _startY;


        const dist = Math.sqrt(dx * dx + dy * dy);
        const clampedDist = Math.min(dist, _maxRadius);
        const angle = Math.atan2(dy, dx);

        const clampedX = Math.cos(angle) * clampedDist;
        const clampedY = Math.sin(angle) * clampedDist;


        _stick.style.transform = `translate(calc(-50% + ${clampedX}px), calc(-50% + ${clampedY}px))`;


        _outputX = clampedX / _maxRadius;
        _outputY = clampedY / _maxRadius;


        if (Math.abs(_outputX) < _deadzone) _outputX = 0;
        if (Math.abs(_outputY) < _deadzone) _outputY = 0;

        if (_onMove) _onMove(_outputX, _outputY);
    }

    function onEnd(e) {
        if (!_active) return;
        _active = false;
        _stick.classList.remove('active');


        _stick.style.transform = 'translate(-50%, -50%)';
        _outputX = 0;
        _outputY = 0;

        if (_onRelease) _onRelease();
    }


    function getX() { return _outputX; }
    function getY() { return _outputY; }
    function getVector() { return { x: _outputX, y: _outputY }; }
    function isActive() { return _active; }


    function onMoveCallback(fn) { _onMove = fn; }
    function onReleaseCallback(fn) { _onRelease = fn; }


    function setDeadzone(value) { _deadzone = value; }
    function setMaxRadius(value) { _maxRadius = value; }


    function destroy() {
        if (_container) {
            _container.remove();
            _container = null;
            _base = null;
            _stick = null;
        }
        window.removeEventListener('mousemove', onMove);
        window.removeEventListener('touchmove', onMove);
        window.removeEventListener('mouseup', onEnd);
        window.removeEventListener('touchend', onEnd);
    }


    function show() { if (_container) _container.style.display = 'block'; }
    function hide() { if (_container) _container.style.display = 'none'; }


    return {
        create,
        destroy,
        getX,
        getY,
        getVector,
        isActive,
        onMove: onMoveCallback,
        onRelease: onReleaseCallback,
        setDeadzone,
        setMaxRadius,
        show,
        hide
    };
})();

if (typeof module !== 'undefined' && module.exports) {
    module.exports = JoystickSubstrate;
}
